import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import SearchBar from './components/SearchBar';
import { SparklesIcon, GlobeAltIcon, BookOpenIcon } from './components/icons';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

interface GroundingSource {
  title: string;
  uri: string;
}

export default function App() {
  const [query, setQuery] = useState<string>('');
  const [isSearching, setIsSearching] = useState(false);
  const [answer, setAnswer] = useState<string | null>(null);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [error, setError] = useState<string | null>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  const handleSearch = async (submittedQuery: string) => {
    if (!submittedQuery.trim()) return;

    setQuery(submittedQuery);
    setIsSearching(true);
    setError(null);
    setAnswer('');
    setSources([]);

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: submittedQuery,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "No response generated.";
      setAnswer(text);

      // Extract sources
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const extractedSources: GroundingSource[] = chunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri,
        }));

      // De-duplicate sources
      const uniqueSources = Array.from(new Map(extractedSources.map(s => [s.uri, s])).values());
      setSources(uniqueSources);

    } catch (err) {
      console.error(err);
      setError("An error occurred while searching. Please try again.");
    } finally {
      setIsSearching(false);
    }
  };

  useEffect(() => {
    if (answer && resultRef.current) {
      resultRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [answer]);

  return (
    <main className="min-h-screen bg-slate-50 dark:bg-gray-950 text-gray-900 dark:text-gray-100 transition-colors duration-500">
      {/* Background decoration */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none -z-10">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-500/5 rounded-full blur-[120px]"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-500/5 rounded-full blur-[120px]"></div>
      </div>

      <div className={`flex flex-col items-center transition-all duration-700 ease-in-out ${answer || isSearching ? 'pt-8' : 'justify-center h-screen'}`}>
        {/* Header / Logo */}
        <div className={`text-center space-y-4 transition-all duration-700 ${answer || isSearching ? 'scale-75 opacity-80 mb-4' : 'mb-12'}`}>
          <h1 className="text-6xl md:text-8xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-indigo-500 via-purple-500 to-pink-500 drop-shadow-sm select-none">
            Searchify
          </h1>
          {!answer && !isSearching && (
            <p className="text-gray-500 dark:text-gray-400 text-lg md:text-xl max-w-lg mx-auto font-medium">
              Intelligent insights from the entire web.
            </p>
          )}
        </div>

        {/* Search Input Container */}
        <div className={`w-full max-w-3xl px-6 transition-all duration-700 ${answer || isSearching ? 'sticky top-4 z-50' : ''}`}>
          <SearchBar onSearch={handleSearch} initialQuery={query} />
        </div>

        {/* Results Area */}
        {(isSearching || answer || error) && (
          <div ref={resultRef} className="w-full max-w-3xl px-6 py-12 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {isSearching && (
              <div className="flex flex-col items-center justify-center space-y-4 py-20">
                <div className="relative w-16 h-16">
                  <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                </div>
                <p className="text-indigo-500 font-medium animate-pulse">Searching the web...</p>
              </div>
            )}

            {error && (
              <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl text-red-600 dark:text-red-400 text-center">
                {error}
              </div>
            )}

            {answer && (
              <div className="space-y-10">
                {/* AI Response Section */}
                <section className="bg-white dark:bg-gray-900 p-8 rounded-3xl shadow-xl shadow-indigo-500/5 border border-gray-100 dark:border-gray-800 leading-relaxed text-lg">
                  <div className="flex items-center space-x-2 mb-6 text-indigo-500 font-bold uppercase tracking-widest text-xs">
                    <SparklesIcon className="w-4 h-4" />
                    <span>AI Insight</span>
                  </div>
                  <div className="prose prose-indigo dark:prose-invert max-w-none whitespace-pre-wrap">
                    {answer}
                  </div>
                </section>

                {/* Sources Section */}
                {sources.length > 0 && (
                  <section className="space-y-4">
                    <div className="flex items-center space-x-2 text-gray-500 dark:text-gray-400 font-bold uppercase tracking-widest text-xs ml-2">
                      <GlobeAltIcon className="w-4 h-4" />
                      <span>Verified Sources</span>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {sources.map((source, idx) => (
                        <a
                          key={idx}
                          href={source.uri}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="group flex flex-col p-4 bg-white dark:bg-gray-900/50 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 border border-gray-100 dark:border-gray-800 rounded-2xl transition-all duration-200 hover:scale-[1.02] hover:shadow-lg"
                        >
                          <span className="text-sm font-semibold text-gray-900 dark:text-gray-100 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 line-clamp-1">
                            {source.title}
                          </span>
                          <span className="text-xs text-gray-500 dark:text-gray-500 mt-1 line-clamp-1">
                            {new URL(source.uri).hostname}
                          </span>
                        </a>
                      ))}
                    </div>
                  </section>
                )}
              </div>
            )}
          </div>
        )}
      </div>

      <footer className="py-12 text-center text-gray-400 dark:text-gray-600 text-xs font-medium tracking-widest uppercase">
        © 2024 Searchify AI Experience
      </footer>
    </main>
  );
}

